    /**
     * @method
     * @name coinmetro#fetchCurrencies
     * @description fetches all available currencies on an exchange
     * @see https://documenter.getpostman.com/view/3653795/SVfWN6KS#d5876d43-a3fe-4479-8c58-24d0f044edfb
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} an associative dictionary of currencies
     */
    public java.util.concurrent.CompletableFuture<Object> fetchCurrencies(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            Object response = (this.publicGetAssets(parameters)).join();
            //
            //     [
            //         {
            //             "symbol": "BTC",
            //             "name": "Bitcoin",
            //             "color": "#FFA500",
            //             "type": "coin",
            //             "canDeposit": true,
            //             "canWithdraw": true,
            //             "canTrade": true,
            //             "notabeneDecimals": 8,
            //             "canMarket": true,
            //             "maxSwap": 10000,
            //             "digits": 6,
            //             "multiplier": 1000000,
            //             "bookDigits": 8,
            //             "bookMultiplier": 100000000,
            //             "sentimentData": {
            //                 "sentiment": 51.59555555555555,
            //                 "interest": 1.127511216044664
            //             },
            //             "minQty": 0.0001
            //         },
            //         {
            //             "symbol": "EUR",
            //             "name": "Euro",
            //             "color": "#1246FF",
            //             "type": "fiat",
            //             "canDeposit": true,
            //             "canWithdraw": true,
            //             "canTrade": true,
            //             "canMarket": true,
            //             "maxSwap": 10000,
            //             "digits": 2,
            //             "multiplier": 100,
            //             "bookDigits": 3,
            //             "bookMultiplier": 1000,
            //             "minQty": 5
            //         }
            //         ...
            //     ]
            //
            Object result = this.parseCurrencies(response);
            Object currenciesById = this.indexBy(result, "id");
            Helpers.addElementToObject(this.options, "currenciesByIdForParseMarket", currenciesById);
            Object currentCurrencyIdsList = this.safeList(this.options, "currencyIdsListForParseMarket", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            Object currencyIdsList = Helpers.objectKeys(currenciesById);
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(currencyIdsList)); i++)
            {
                ((java.util.List<Object>)currentCurrencyIdsList).add(Helpers.GetValue(currencyIdsList, i));
            }
            Helpers.addElementToObject(this.options, "currencyIdsListForParseMarket", currentCurrencyIdsList);
            return result;
        });

    }

    public Object parseCurrency(Object rawCurrency)
    {
        Object id = this.safeString(rawCurrency, "symbol");
        Object code = this.safeCurrencyCode(id);
        Object typeRaw = this.safeString(rawCurrency, "type");
        Object type = null;
        if (Helpers.isTrue(Helpers.isTrue(Helpers.isTrue(Helpers.isTrue(Helpers.isEqual(typeRaw, "coin")) || Helpers.isTrue(Helpers.isEqual(typeRaw, "token"))) || Helpers.isTrue(Helpers.isEqual(typeRaw, "erc20"))) || Helpers.isTrue(Helpers.isEqual(typeRaw, "crypto"))))
        {
            type = "crypto";
        } else if (Helpers.isTrue(Helpers.isEqual(typeRaw, "fiat")))
        {
            type = "fiat";
        }
        Object precisionDigits = this.safeString2(rawCurrency, "digits", "notabeneDecimals");
        if (Helpers.isTrue(Helpers.isEqual(code, "RENDER")))
        {
            // RENDER is an exception (with broken info)
            precisionDigits = "4";
        }
        final Object finalCode = code;
        final Object finalType = type;
        final Object finalPrecisionDigits = precisionDigits;
        return this.safeCurrencyStructure(new java.util.HashMap<String, Object>() {{
            put( "id", id );
            put( "code", finalCode );
            put( "name", finalCode );
            put( "type", finalType );
            put( "info", rawCurrency );
            put( "active", CoinmetroCore.this.safeBool(rawCurrency, "canTrade") );
            put( "deposit", CoinmetroCore.this.safeBool(rawCurrency, "canDeposit") );
            put( "withdraw", CoinmetroCore.this.safeBool(rawCurrency, "canWithdraw") );
            put( "fee", null );
            put( "precision", CoinmetroCore.this.parseNumber(CoinmetroCore.this.parsePrecision(finalPrecisionDigits)) );
            put( "limits", new java.util.HashMap<String, Object>() {{
                put( "amount", new java.util.HashMap<String, Object>() {{
                    put( "min", CoinmetroCore.this.safeNumber(rawCurrency, "minQty") );
                    put( "max", null );
                }} );
                put( "withdraw", new java.util.HashMap<String, Object>() {{
                    put( "min", null );
                    put( "max", null );
                }} );
            }} );
            put( "networks", new java.util.HashMap<String, Object>() {{}} );
        }});
    }

    /**
     * @method
     * @name coinmetro#fetchMarkets
     * @description retrieves data on all markets for coinmetro
     * @see https://documenter.getpostman.com/view/3653795/SVfWN6KS#9fd18008-338e-4863-b07d-722878a46832
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object[]} an array of objects representing market data
     */
    public java.util.concurrent.CompletableFuture<Object> fetchMarkets(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            Object promises = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            ((java.util.List<Object>)promises).add(this.publicGetMarkets(parameters));
            Object responses = (Helpers.promiseAll(promises)).join();
            Object response = Helpers.GetValue(responses, 0);
            //
            //     [
            //         {
            //             "pair": "YFIEUR",
            //             "precision": 5,
            //             "margin": false
            //         },
            //         {
            //             "pair": "BTCEUR",
            //             "precision": 2,
            //             "margin": true
            //         },
            //         ...
            //     ]
            //
            Object result = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(response)); i++)
            {
                Object market = this.parseMarket(Helpers.GetValue(response, i));
                // there are several broken (unavailable info) markets
                if (Helpers.isTrue(Helpers.isTrue(Helpers.isEqual(this.safeString(market, "base"), null)) || Helpers.isTrue(Helpers.isEqual(this.safeString(market, "quote"), null))))
                {
                    continue;
                }
                ((java.util.List<Object>)result).add(market);
            }
            return result;
        });

    }

    public Object parseMarket(Object market)
    {
        Object id = this.safeString(market, "pair");
        Object parsedMarketId = this.parseMarketId(id);
        Object baseId = this.safeString(parsedMarketId, "baseId");
        Object quoteId = this.safeString(parsedMarketId, "quoteId");
        Object base = this.safeCurrencyCode(baseId);
        Object quote = this.safeCurrencyCode(quoteId);
        Object basePrecisionAndLimits = this.parseMarketPrecisionAndLimits(baseId);
        Object quotePrecisionAndLimits = this.parseMarketPrecisionAndLimits(quoteId);
        Object margin = this.safeBool(market, "margin", false);
        Object tradingFees = this.safeValue(this.fees, "trading", new java.util.HashMap<String, Object>() {{}});
        final Object finalBase = base;
        return this.safeMarketStructure(new java.util.HashMap<String, Object>() {{
            put( "id", id );
            put( "symbol", Helpers.add(Helpers.add(finalBase, "/"), quote) );
            put( "base", finalBase );
            put( "quote", quote );
            put( "settle", null );
            put( "baseId", baseId );
            put( "quoteId", quoteId );
            put( "settleId", null );
            put( "type", "spot" );
            put( "spot", true );
            put( "margin", margin );
            put( "swap", false );
            put( "future", false );
            put( "option", false );
            put( "active", true );
            put( "contract", false );
            put( "linear", null );
            put( "inverse", null );
            put( "taker", CoinmetroCore.this.safeNumber(tradingFees, "taker") );
            put( "maker", CoinmetroCore.this.safeNumber(tradingFees, "maker") );
            put( "contractSize", null );
            put( "expiry", null );
            put( "expiryDatetime", null );
            put( "strike", null );
            put( "optionType", null );
            put( "precision", new java.util.HashMap<String, Object>() {{
                put( "amount", Helpers.GetValue(basePrecisionAndLimits, "precision") );
                put( "price", CoinmetroCore.this.parseNumber(CoinmetroCore.this.parsePrecision(CoinmetroCore.this.safeString(market, "precision"))) );
            }} );
            put( "limits", new java.util.HashMap<String, Object>() {{
                put( "leverage", new java.util.HashMap<String, Object>() {{
                    put( "min", null );
                    put( "max", null );
                }} );
                put( "amount", new java.util.HashMap<String, Object>() {{
                    put( "min", Helpers.GetValue(basePrecisionAndLimits, "minLimit") );
                    put( "max", null );
                }} );
                put( "price", new java.util.HashMap<String, Object>() {{
                    put( "min", null );
                    put( "max", null );
                }} );
                put( "cost", new java.util.HashMap<String, Object>() {{
                    put( "min", Helpers.GetValue(quotePrecisionAndLimits, "minLimit") );
                    put( "max", null );
                }} );
            }} );
            put( "created", null );
            put( "info", market );
        }});
    }

    public Object parseMarketId(Object marketId)
    {
        Object baseId = null;
        Object quoteId = null;
        Object currencyIds = this.safeValue(this.options, "currencyIdsListForParseMarket", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        // Bubble sort by length (longest first)
        Object currencyIdsLength = Helpers.getArrayLength(currencyIds);
        for (var i = 0; Helpers.isLessThan(i, currencyIdsLength); i++)
        {
            for (var j = 0; Helpers.isLessThan(j, Helpers.subtract(Helpers.subtract(currencyIdsLength, i), 1)); j++)
            {
                Object a = Helpers.GetValue(currencyIds, j);
                Object b = Helpers.GetValue(currencyIds, Helpers.add(j, 1));
                if (Helpers.isTrue(Helpers.isLessThan(Helpers.getArrayLength(a), Helpers.getArrayLength(b))))
                {
                    Helpers.addElementToObject(currencyIds, j, b);
                    Helpers.addElementToObject(currencyIds, Helpers.add(j, 1), a);
                }
            }
        }
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(currencyIds)); i++)
        {
            Object currencyId = Helpers.GetValue(currencyIds, i);
            Object entryIndex = Helpers.getIndexOf(marketId, currencyId);
            if (Helpers.isTrue(Helpers.isEqual(entryIndex, 0)))
            {
                Object restId = Helpers.replace((String)marketId, (String)currencyId, (String)"");
                if (Helpers.isTrue(this.inArray(restId, currencyIds)))
                {
                    if (Helpers.isTrue(Helpers.isEqual(entryIndex, 0)))
                    {
                        baseId = currencyId;
                        quoteId = restId;
                    } else
                    {
                        baseId = restId;
                        quoteId = currencyId;
                    }
                    break;
                }
            }
        }
        if (Helpers.isTrue(Helpers.isTrue(Helpers.isEqual(baseId, null)) || Helpers.isTrue(Helpers.isEqual(quoteId, null))))
        {
            // https://github.com/ccxt/ccxt/issues/26820
            if (Helpers.isTrue(((String)marketId).endsWith(((String)"USDT"))))
            {
                baseId = Helpers.replace((String)marketId, (String)"USDT", (String)"");
                quoteId = "USDT";
            }
            if (Helpers.isTrue(((String)marketId).endsWith(((String)"USD"))))
            {
                baseId = Helpers.replace((String)marketId, (String)"USD", (String)"");
                quoteId = "USD";
            }
        }
        final Object finalBaseId = baseId;
        final Object finalQuoteId = quoteId;
        Object result = new java.util.HashMap<String, Object>() {{
            put( "baseId", finalBaseId );
            put( "quoteId", finalQuoteId );
        }};
        return result;
    }

    public Object parseMarketPrecisionAndLimits(Object currencyId)
    {
        Object currencies = this.safeValue(this.options, "currenciesByIdForParseMarket", new java.util.HashMap<String, Object>() {{}});
        Object currency = this.safeValue(currencies, currencyId, new java.util.HashMap<String, Object>() {{}});
        Object limits = this.safeValue(currency, "limits", new java.util.HashMap<String, Object>() {{}});
        Object amountLimits = this.safeValue(limits, "amount", new java.util.HashMap<String, Object>() {{}});
        Object minLimit = this.safeNumber(amountLimits, "min");
        Object result = new java.util.HashMap<String, Object>() {{
            put( "precision", CoinmetroCore.this.safeNumber(currency, "precision") );
            put( "minLimit", minLimit );
        }};
        return result;
    }

    /**
     * @method
     * @name coinmetro#fetchOHLCV
     * @description fetches historical candlestick data containing the open, high, low, and close price, and the volume of a market
     * @see https://documenter.getpostman.com/view/3653795/SVfWN6KS#13cfb5bc-7bfb-4847-85e1-e0f35dfb3573
     * @param {string} symbol unified symbol of the market to fetch OHLCV data for
     * @param {string} timeframe the length of time each candle represents
     * @param {int} [since] timestamp in ms of the earliest candle to fetch
     * @param {int} [limit] the maximum amount of candles to fetch
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {int} [params.until] the latest time in ms to fetch entries for
     * @returns {int[][]} A list of candles ordered as timestamp, open, high, low, close, volume
     */
    public java.util.concurrent.CompletableFuture<Object> fetchOHLCV(Object symbol, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object timeframe = Helpers.getArg(optionalArgs, 0, "1m");
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object market = this.market(symbol);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "pair", Helpers.GetValue(market, "id") );
                put( "timeframe", CoinmetroCore.this.safeString(CoinmetroCore.this.timeframes, timeframe, timeframe) );
            }};
            Object until = null;
            if (Helpers.isTrue(!Helpers.isEqual(since, null)))
            {
                Helpers.addElementToObject(request, "from", since);
                if (Helpers.isTrue(!Helpers.isEqual(limit, null)))
                {
                    Object duration = Helpers.multiply(this.parseTimeframe(timeframe), 1000);
                    until = this.sum(since, Helpers.multiply(duration, (limit)));
                }
            } else
            {
                Helpers.addElementToObject(request, "from", ":from"); // this endpoint doesn't accept empty from and to params (setting them into the value described in the documentation)
            }
            until = this.safeInteger(parameters, "until", until);
            if (Helpers.isTrue(!Helpers.isEqual(until, null)))
            {
                parameters = this.omit(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("until")));
                Helpers.addElementToObject(request, "to", until);
            } else
            {
                Helpers.addElementToObject(request, "to", ":to");
            }
            Object response = (this.publicGetExchangeCandlesPairTimeframeFromTo(this.extend(request, parameters))).join();
            //
            //     {
            //         "candleHistory": [
            //             {
            //                 "pair": "ETHUSDT",
            //                 "timeframe": 86400000,
            //                 "timestamp": 1697673600000,
            //                 "c": 1567.4409353098604,
            //                 "h": 1566.7514068472303,
            //                 "l": 1549.4563666936847,
            //                 "o": 1563.4490341395904,
            //                 "v": 0
            //             },
            //             {
            //                 "pair": "ETHUSDT",
            //                 "timeframe": 86400000,
            //                 "timestamp": 1697760000000,
            //                 "c": 1603.7831363339324,
            //                 "h": 1625.0356823666407,
            //                 "l": 1565.4629390011505,
            //                 "o": 1566.8387619426028,
            //                 "v": 0
            //             },
            //             ...
            //         ]
            //     }
            //
            Object candleHistory = this.safeList(response, "candleHistory", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            return this.parseOHLCVs(candleHistory, market, timeframe, since, limit);
        });

    }

