    public Object parseTrade(Object trade, Object... optionalArgs)
    {
        //
        // fetchTrades
        //     {
        //         "pair": "ETHUSDT",
        //         "price": 2077.1513,
        //         "qty": 0.00337,
        //         "timestamp": 1700684816853,
        //         "seqNum": 10644567113
        //     },
        //
        // fetchMyTrades
        //     {
        //         "pair": "ETHUSDC",
        //         "seqNumber": 10873722343,
        //         "timestamp": 1702570610747,
        //         "qty": 0.002,
        //         "price": 2282,
        //         "side": "buy",
        //         "orderID": "65671262d93d9525ac009e36170257061073952c6423a8c5b4d6c"
        //     }
        //
        // fetchOrders
        //     {
        //         "_id": "657b31d360a9542449381bdc",
        //         "seqNumber": 10873722343,
        //         "timestamp": 1702570610747,
        //         "qty": 0.002,
        //         "price": 2282,
        //         "side": "buy"
        //     }
        //
        //    {
        //        "pair":"ETHUSDC",
        //        "seqNumber":"10873722343",
        //        "timestamp":"1702570610747",
        //        "qty":"0.002",
        //        "price":"2282",
        //        "side":"buy",
        //        "orderID":"65671262d93d9525ac009e36170257061073952c6423a8c5b4d6c",
        //        "userID":"65671262d93d9525ac009e36"
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marketId = this.safeString2(trade, "symbol", "pair");
        market = this.safeMarket(marketId, market);
        Object symbol = Helpers.GetValue(market, "symbol");
        Object id = this.safeStringN(trade, new java.util.ArrayList<Object>(java.util.Arrays.asList("_id", "seqNum", "seqNumber")));
        Object timestamp = this.safeInteger(trade, "timestamp");
        Object priceString = this.safeString(trade, "price");
        Object amountString = this.safeString(trade, "qty");
        Object order = this.safeString(trade, "orderID");
        Object side = this.safeString(trade, "side");
        return this.safeTrade(new java.util.HashMap<String, Object>() {{
            put( "id", id );
            put( "order", order );
            put( "timestamp", timestamp );
            put( "datetime", CoinmetroCore.this.iso8601(timestamp) );
            put( "symbol", symbol );
            put( "type", null );
            put( "side", side );
            put( "takerOrMaker", null );
            put( "price", priceString );
            put( "amount", amountString );
            put( "cost", null );
            put( "fee", null );
            put( "info", trade );
        }}, market);
    }

