            //
            //     {
            //         "book": {
            //             "pair": "ETHUSDT",
            //             "seqNumber": 10800409239,
            //             "ask": {
            //                 "2354.2861": 3.75,
            //                 "2354.3138": 19,
            //                 "2354.7538": 80,
            //                 "2355.5430": 260,
            //                 "2356.4611": 950,
            //                 "2361.7150": 1500,
