    public Object parseOrderBookBidsAsks(Object bidasks, Object... optionalArgs)
    {
        Object priceKey = Helpers.getArg(optionalArgs, 0, 0);
        Object amountKey = Helpers.getArg(optionalArgs, 1, 1);
        Object countOrIdKey = Helpers.getArg(optionalArgs, 2, 2);
        Object prices = Helpers.objectKeys(bidasks);
        Object result = new java.util.ArrayList<Object>(java.util.Arrays.asList());
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(prices)); i++)
        {
            Object priceString = this.safeString(prices, i);
            Object price = this.safeNumber(prices, i);
            Object volume = this.safeNumber(bidasks, priceString);
            ((java.util.List<Object>)(result)).add(new java.util.ArrayList<Object>(java.util.Arrays.asList(price, volume)));
        }
        return result;
    }

    /**
     * @method
     * @name coinmetro#fetchTickers
     * @description fetches price tickers for multiple markets, statistical information calculated over the past 24 hours for each market
     * @see https://documenter.getpostman.com/view/3653795/SVfWN6KS#6ecd1cd1-f162-45a3-8b3b-de690332a485
     * @param {string[]} [symbols] unified symbols of the markets to fetch the ticker for, all market tickers are returned if not assigned
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} a dictionary of [ticker structures]{@link https://docs.ccxt.com/?id=ticker-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchTickers(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object symbols = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object response = (this.publicGetExchangePrices(parameters)).join();
            //
            //     {
            //         "latestPrices": [
            //             {
            //                 "pair": "PERPEUR",
            //                 "timestamp": 1702549840393,
            //                 "price": 0.7899997816001223,
            //                 "qty": 1e-12,
            //                 "ask": 0.8,
            //                 "bid": 0.7799995632002446
            //             },
            //             {
            //                 "pair": "PERPUSD",
            //                 "timestamp": 1702549841973,
            //                 "price": 0.8615317721366659,
            //                 "qty": 1e-12,
            //                 "ask": 0.8742333599999257,
            //                 "bid": 0.8490376365388491
            //             },
            //             ...
            //         ],
            //         "24hInfo": [
            //             {
            //                 "delta": 0.25396444229149906,
            //                 "h": 0.78999978160012,
            //                 "l": 0.630001740844,
            //                 "v": 54.910000002833996,
            //                 "pair": "PERPEUR",
            //                 "sentimentData": {
            //                     "sentiment": 36.71333333333333,
            //                     "interest": 0.47430830039525695
            //                     }
            //                 },
            //             {
            //                 "delta": 0.26915154078134096,
            //                 "h": 0.86220315458898,
            //                 "l": 0.67866757035154,
            //                 "v": 2.835000000000001e-9,
            //                 "pair": "PERPUSD",
            //                 "sentimentData": {
            //                     "sentiment": 36.71333333333333,
            //                     "interest": 0.47430830039525695
            //                 }
            //             },
            //             ...
            //         ]
            //     }
            //
            Object latestPrices = this.safeValue(response, "latestPrices", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            Object twentyFourHInfos = this.safeValue(response, "24hInfo", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            Object tickersObject = new java.util.HashMap<String, Object>() {{}};
            // merging info from two lists into one
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(latestPrices)); i++)
            {
                Object latestPrice = Helpers.GetValue(latestPrices, i);
                Object marketId = this.safeString(latestPrice, "pair");
                if (Helpers.isTrue(!Helpers.isEqual(marketId, null)))
                {
                    Helpers.addElementToObject(tickersObject, marketId, latestPrice);
                }
            }
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(twentyFourHInfos)); i++)
            {
                Object twentyFourHInfo = Helpers.GetValue(twentyFourHInfos, i);
                Object marketId = this.safeString(twentyFourHInfo, "pair");
                if (Helpers.isTrue(!Helpers.isEqual(marketId, null)))
                {
                    Object latestPrice = this.safeValue(tickersObject, marketId, new java.util.HashMap<String, Object>() {{}});
                    Helpers.addElementToObject(tickersObject, marketId, this.extend(twentyFourHInfo, latestPrice));
                }
            }
            Object tickers = Helpers.objectValues(tickersObject);
            return this.parseTickers(tickers, symbols);
        });

    }

