    /**
     * @method
     * @name coinmetro#fetchBalance
     * @description query for balance and get the amount of funds available for trading or funds locked in orders
     * @see https://documenter.getpostman.com/view/3653795/SVfWN6KS#741a1dcc-7307-40d0-acca-28d003d1506a
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} a [balance structure]{@link https://docs.ccxt.com/?id=balance-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchBalance(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object response = (this.privateGetUsersWallets(parameters)).join();
            Object list = this.safeList(response, "list", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            return this.parseBalance(list);
        });

    }

    public Object parseBalance(Object balances)
    {
        //
        //     [
        //         {
        //             "xcmLocks": [],
        //             "xcmLockAmounts": [],
        //             "refList": [],
        //             "balanceHistory": [],
        //             "_id": "5fecd3c998e75c2e4d63f7c3",
        //             "currency": "BTC",
        //             "label": "BTC",
        //             "userId": "5fecd3c97fbfed1521db23bd",
        //             "__v": 0,
        //             "balance": 0.5,
        //             "createdAt": "2020-12-30T19:23:53.646Z",
        //             "disabled": false,
        //             "updatedAt": "2020-12-30T19:23:53.653Z",
        //             "reserved": 0,
        //             "id": "5fecd3c998e75c2e4d63f7c3"
        //         },
        //         ...
        //     ]
        //
        Object result = new java.util.HashMap<String, Object>() {{
            put( "info", balances );
        }};
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(balances)); i++)
        {
            Object balanceEntry = this.safeDict(balances, i, new java.util.HashMap<String, Object>() {{}});
            Object currencyId = this.safeString(balanceEntry, "currency");
            Object code = this.safeCurrencyCode(currencyId);
            Object account = this.account();
            Helpers.addElementToObject(account, "total", this.safeString(balanceEntry, "balance"));
            Helpers.addElementToObject(account, "used", this.safeString(balanceEntry, "reserved"));
            Helpers.addElementToObject(result, code, account);
        }
        return this.safeBalance(result);
    }

