            (this.loadMarkets()).join();
            Object request = new java.util.HashMap<String, Object>() {{}};
            if (Helpers.isTrue(!Helpers.isEqual(since, null)))
            {
                Helpers.addElementToObject(request, "since", since);
            } else
            {
                // this endpoint accepts empty since param
                Helpers.addElementToObject(request, "since", "");
            }
            Object currency = null;
            if (Helpers.isTrue(!Helpers.isEqual(code, null)))
            {
                currency = this.currency(code);
            }
            Object response = (this.privateGetUsersWalletsHistorySince(this.extend(request, parameters))).join();
            //
